聊天室的package mainimport ( &quot;fmt&quot; &quot;net&quot; &quot;strings&quot; &quot;sync&quot; &quot;time&quot;)func main() &#123; startServer()&#125;type Userxx struct &#123; id string name string msg chan string&#125;// km 全局map// km 第二种方式无法在全局作用域使用，因为： 短变量声明（:=）只能在函数内部使用// 全局作用域必须使用 var 关键字或类型推导的 var 声明 Go 语言规范明确规定短变量声明不能用于包级别作用域var userMap = make(map[string]Userxx)var lock2 sync.RWMutex//userMap:=make(map[string]Userxx)// km 全局通道var allMessageChannel = make(chan string, 10)func startServer() &#123; //创建监听 ip := &quot;127.0.0.1&quot; port := 8089 address := fmt.Sprintf(&quot;%s:%d&quot;, ip, port) listener, err := net.Listen(&quot;tcp&quot;, address) if err != nil &#123; fmt.Println(&quot;net.Listen err:&quot;, err) return &#125; fmt.Println(&quot;server start success ...&quot;) fmt.Println(&quot;ready to start server broadcastxx goroutine ...&quot;) go broadcastxx() fmt.Println(&quot; ready to receive client connect ...&quot;) for &#123; //Accept() (Conn, error) conn, err := listener.Accept() if err != nil &#123; fmt.Println(&quot;listener.Accept err:&quot;, err) return &#125; fmt.Println(&quot;one client connect success !&quot;) go handleFunc_len(conn) &#125;&#125;// 处理具体业务的逻辑，需要将conn传递进来，每一新连接，conn是不同的func handleFunc_len(conn net.Conn) &#123; // 01 计算机会随机分配给客户端port clientAddr := conn.RemoteAddr().String() fmt.Println(&quot;当前登录用户:&quot;, clientAddr) name := fmt.Sprintf(&quot;clientName%s&quot;, clientAddr) clientId := fmt.Sprintf(&quot;clientId%s&quot;, clientAddr) newUserxy := Userxx&#123; name: name, // 可以修改 id: clientId, msg: make(chan string, 5), // 一定要分配空间 &#125; //02 添加user到map,维护 //km 处理并发问题 lock2.Lock() userMap[newUserxy.id] = newUserxy lock2.Unlock() // 03 启动goroutine 负责将每个user接受到总allMessageChannel 推给当前用户的广播信息 go writeBack(&amp;newUserxy, conn) //04 全局管道写入数据， 当前用户上线，全局广播 //loginInfo := fmt.Sprintf(&quot;[%s]:[%s] ===&gt; 上线了 login!!&quot;, newUser.id, newUser.name) loginInfo := fmt.Sprintf(&quot;%s =&gt;loginIn&quot;, newUserxy.name) allMessageChannel &lt;- loginInfo // watch dog 延迟 连接存活时间 //restTimer &lt;- chan int var restTimer = make(chan int) // 全局退出信号 isQuit := make(chan bool) go watchxxx(&amp;newUserxy, conn, isQuit, restTimer) for &#123; //这个for循环，保证每一个连接可以多次接收处理客户端请求 //01 1 创建一个容器，用于接收读取到的数据 buf := make([]byte, 1024) //使用make来创建字节切片, byte ==&gt; uint8 fmt.Println(&quot;准备读取客户端发送的数据....&quot;) //Read(b []byte) (n int, err error) //02 nt：真正读取client发来的数据的长度 cnt, err := conn.Read(buf) // 退出时候 两种情况 分别是 主动和超时 // ctrl+c 时候 cnt==0 if cnt == 0 &#123; fmt.Println(&quot;客户端主动关闭ctrl + c，准备退出, err:&quot;, err) //map删除，用户， conn close掉 //服务器还可以主动的退出 //在这里不进行真正的退出动作，而是发送一个退出信号，统一做退出处理，可以使用新的管道来做信号传递 isQuit &lt;- true &#125; if err != nil &#123; fmt.Println(&quot;conn.Read err:&quot;, err) return &#125; content := string(buf[:cnt-1]) fmt.Println(&quot;Client =====&gt; Server, 长度:&quot;, cnt-1, &quot;，数据:&quot;, content) if len(content) == 0 &#123; // 处理空字符串的逻辑 restTimer &lt;- 100 continue &#125; // 查询所有用户逻辑 // 数组切片 var userInfos []string if len(content) == 3 &amp;&amp; string(content) == &quot;who&quot; &#123; fmt.Println(&quot;查询所有用户信息&quot;) for _, userxx := range userMap &#123; userInfox := fmt.Sprintf(&quot;userId:%s,userName:%s&quot;, userxx.id, userxx.name) userInfos = append(userInfos, userInfox) &#125; // slice:: [userId:clientId127.0.0.1:19736,userName:clientName127.0.0.1:19736 userId:clientId127.0.0.1:19739,userName:clientName127.0.0.1:19739] fmt.Println(&quot;slice::&quot;, userInfos) // 转换成字符串放入管道 //userId:clientId127.0.0.1:19777,userName:clientName127.0.0.1:19777 r := strings.Join(userInfos, &quot;
&quot;) //km 只是写给当前客户 newUserxy.msg &lt;- r &#125; else if len(content) &gt; 7 &amp;&amp; content[:6] == &quot;rename&quot; &#123; //3. 更新用户名字newUser.name = Duke newUserxy.name = strings.Split(content, &quot;|&quot;)[1] userMap[newUserxy.id] = newUserxy //更新map中的user // ////4. 通知客户端，更新成功 newUserxy.msg &lt;- &quot;rename successfully!&quot; &#125; else &#123; // km 普通聊天信息 allMessageChannel &lt;- content &#125; restTimer &lt;- 100 &#125; //关闭连接 _ = conn.Close()&#125;func broadcastxx() &#123; fmt.Println(&quot;broadcastxx start successs,wait broadcast msg&quot;) defer fmt.Println(&quot;broadcastxx goroutine exit&quot;) for &#123; // 最新进入全局管道信息转移到info info := &lt;-allMessageChannel //fmt.Println(&quot;broadcastxx&gt;&gt; 个人message 接收到消息:&quot;, info) //遍历集合 吧信息发给没有在线用户 for _, useri := range userMap &#123; useri.msg &lt;- info &#125; &#125;&#125;// 每个用户应该还有一个用来监听自己msg管道的go程，负责将数据返回给客户端func writeBack(user *Userxx, conn net.Conn) &#123; //name:=user.name fmt.Printf(&quot;current user : %s 的go程正在监听自己的msg管道:
&quot;, user.name) for data := range user.msg &#123; fmt.Println(&quot;地址：：：：：：：：：&quot;, conn.RemoteAddr().String()) fmt.Printf(&quot;user : %s 写回给客户端的数据为:%s
&quot;, user.name, data) //Write(b []byte) (n int, err error) _, _ = conn.Write([]byte(data)) &#125;&#125;//km 用户退出 delete map， close connfunc watchxxx(user *Userxx, conn net.Conn, isQuit chan bool, restTimer &lt;-chan int) &#123; fmt.Println(&quot;start monitor exit signal&quot;) defer fmt.Println(&quot;watch goroutine exit&quot;) for &#123; select &#123; case &lt;-isQuit: //km 自带方法 delete(userMap, user.id) // 通知其他用户 logOutInfo := fmt.Sprintf(&quot;%s exit already&quot;, user.name) allMessageChannel &lt;- logOutInfo conn.Close() return // 注意返回值 func After(d Duration) &lt;-chan Time &#123; case &lt;-time.After(time.Second * 30): //km 自带方法 delete(userMap, user.id) // 通知其他用户 logOutInfo := fmt.Sprintf(&quot;%s timeout exit already&quot;, user.name) fmt.Printf(&quot;用户 %s 超时退出
&quot;, user.name) fmt.Println(logOutInfo) allMessageChannel &lt;- logOutInfo conn.Close() return case &lt;-restTimer: fmt.Printf(&quot;连接%s 重置计数器!
&quot;, user.name) &#125; &#125;&#125;

